        box-shadow: 0 30px 90px rgba(0, 0, 0, 0.6);
        color: #f5f5f7;
      "
    >
      <!-- Header -->
      <div
        style="
          display: flex;
          align-items: flex-start;
          justify-content: space-between;
          gap: 12px;
          padding: 20px 22px 16px;
          border-bottom: 0.5px solid rgba(255, 255, 255, 0.09);
          background: linear-gradient(135deg, rgba(10, 132, 255, 0.16), rgba(94, 92, 230, 0.12));
        "
      >
        <div style="flex: 1; min-width: 0">
          <div style="display: flex; align-items: center; gap: 7px; color: #7fb0ff; font-size: 12px; font-weight: 600">
            <span style="width: 8px; height: 8px; border-radius: 50%; background: #0a84ff"></span>
            编辑可视化总结
          </div>
          <input
            v-model="draft.title"
            placeholder="总结标题"
            :style="inputStyle"
            style="
              margin: 9px 0 6px;
              font-size: 20px;
