              background: rgba(255, 255, 255, 0.06);
            "
          />
          <div style="color: rgba(235, 235, 245, 0.55); font-size: 12px">
            楼层 {{ draft.range.start }} - {{ draft.range.end }}
          </div>
        </div>
        <button :style="iconBtnStyle" title="关闭" @click="$emit('close')">
          <i class="fa-solid fa-times"></i>
        </button>
      </div>

      <!-- Body -->
      <div style="padding: 16px 18px; overflow-y: auto; display: flex; flex-direction: column; gap: 14px">
        <!-- 时间 / 地点 -->
        <div :style="groupStyle">
          <div :style="groupTitleStyle"><i class="fa-regular fa-clock" :style="groupIconStyle"></i> 时间与地点</div>
          <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 10px">
