        </div>

        <!-- 重要事件 -->
        <div :style="groupStyle">
          <div :style="groupHeadRowStyle">
            <span :style="groupTitleInlineStyle"><i class="fa-solid fa-list-check" :style="groupIconStyle"></i> 重要事件</span>
            <button :style="addBtnStyle" @click="draft.events.push('')"><i class="fa-solid fa-plus"></i> 添加</button>
          </div>
          <div style="display: flex; flex-direction: column; gap: 8px">
            <div v-for="(_, index) in draft.events" :key="`event-${index}`" style="display: flex; align-items: center; gap: 8px">
              <span :style="numBadgeStyle">{{ index + 1 }}</span>
              <input v-model="draft.events[index]" placeholder="事件内容" :style="inputStyle" />
              <button :style="delIconStyle" @click="draft.events.splice(index, 1)"><i class="fa-solid fa-trash"></i></button>
            </div>
            <div v-if="!draft.events.length" :style="emptyHintStyle">暂无事件，点「添加」</div>
          </div>
        </div>

        <!-- 角色状态 -->
        <div :style="groupStyle">
          <div :style="groupHeadRowStyle">
            <span :style="groupTitleInlineStyle"><i class="fa-solid fa-users" :style="groupIconStyle"></i> 角色状态</span>
            <button :style="addBtnStyle" @click="addCharacter"><i class="fa-solid fa-plus"></i> 添加角色</button>
          </div>
          <div style="display: flex; flex-direction: column; gap: 10px">
            <div v-for="(character, index) in draft.characters" :key="`character-${index}`" :style="subCardStyle">
              <div style="display: flex; align-items: center; gap: 8px; margin-bottom: 8px">
                <input v-model="character.name" placeholder="角色名" :style="inputStyle" style="font-weight: 600" />
                <button :style="delIconStyle" @click="draft.characters.splice(index, 1)"><i class="fa-solid fa-trash"></i></button>
              </div>
              <input v-model="character.status" placeholder="当前状态" :style="inputStyle" style="margin-bottom: 8px" />
              <input v-model="character.attitude" placeholder="对用户/他人的态度变化" :style="inputStyle" style="margin-bottom: 8px" />
              <textarea v-model="character.memory" placeholder="这段剧情中角色应该记住什么" :style="textareaStyle"></textarea>
            </div>
            <div v-if="!draft.characters.length" :style="emptyHintStyle">暂无角色</div>
          </div>
        </div>

        <!-- 关系变化 -->
        <div :style="groupStyle">
          <div :style="groupHeadRowStyle">
            <span :style="groupTitleInlineStyle"><i class="fa-solid fa-link" :style="groupIconStyle"></i> 关系变化</span>
            <button :style="addBtnStyle" @click="addRelation"><i class="fa-solid fa-plus"></i> 添加关系</button>
          </div>
          <div style="display: flex; flex-direction: column; gap: 10px">
            <div v-for="(relation, index) in draft.relationshipChanges" :key="`relation-${index}`" :style="subCardStyle">
              <div style="display: grid; grid-template-columns: 1fr auto 1fr auto; align-items: center; gap: 8px; margin-bottom: 8px">
                <input v-model="relation.from" placeholder="来源角色" :style="inputStyle" />
                <i class="fa-solid fa-arrow-right-long" style="color: rgba(235,235,245,0.4)"></i>
                <input v-model="relation.to" placeholder="目标角色" :style="inputStyle" />
                <button :style="delIconStyle" @click="draft.relationshipChanges.splice(index, 1)"><i class="fa-solid fa-trash"></i></button>
              </div>
              <input v-model="relation.change" placeholder="变化，例如：信任上升 / 警惕降低" :style="inputStyle" style="margin-bottom: 8px" />
              <textarea v-model="relation.reason" placeholder="变化原因" :style="textareaStyle"></textarea>
            </div>
            <div v-if="!draft.relationshipChanges.length" :style="emptyHintStyle">暂无关系变化</div>
          </div>
        </div>

        <!-- 伏笔 / 待跟进 -->
        <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 14px">
          <div :style="groupStyle">
            <div :style="groupHeadRowStyle">
              <span :style="groupTitleInlineStyle"><i class="fa-solid fa-puzzle-piece" :style="groupIconStyle"></i> 伏笔 / 线索</span>
              <button :style="addBtnStyle" @click="draft.foreshadowing.push('')"><i class="fa-solid fa-plus"></i></button>
            </div>
            <div style="display: flex; flex-direction: column; gap: 8px">
              <div v-for="(_, index) in draft.foreshadowing" :key="`fs-${index}`" style="display: flex; align-items: center; gap: 8px">
                <span style="flex: 0 0 auto; width: 7px; height: 7px; border-radius: 50%; background: #ff9f0a"></span>
                <input v-model="draft.foreshadowing[index]" placeholder="隐藏线索、未揭示秘密" :style="inputStyle" />
                <button :style="delIconStyle" @click="draft.foreshadowing.splice(index, 1)"><i class="fa-solid fa-trash"></i></button>
              </div>
              <div v-if="!draft.foreshadowing.length" :style="emptyHintStyle">暂无</div>
            </div>
          </div>
          <div :style="groupStyle">
            <div :style="groupHeadRowStyle">
              <span :style="groupTitleInlineStyle"><i class="fa-regular fa-circle-check" :style="groupIconStyle"></i> 待跟进</span>
              <button :style="addBtnStyle" @click="draft.todo.push('')"><i class="fa-solid fa-plus"></i></button>
            </div>
            <div style="display: flex; flex-direction: column; gap: 8px">
              <div v-for="(_, index) in draft.todo" :key="`todo-${index}`" style="display: flex; align-items: center; gap: 8px">
                <span style="flex: 0 0 auto; width: 7px; height: 7px; border-radius: 50%; background: #0a84ff"></span>
                <input v-model="draft.todo[index]" placeholder="下次应继续处理的事" :style="inputStyle" />
                <button :style="delIconStyle" @click="draft.todo.splice(index, 1)"><i class="fa-solid fa-trash"></i></button>
              </div>
              <div v-if="!draft.todo.length" :style="emptyHintStyle">暂无</div>
            </div>
          </div>
        </div>

        <!-- 世界书候选 -->
        <div :style="groupStyle">
          <div :style="groupHeadRowStyle">
            <span :style="groupTitleInlineStyle"><i class="fa-solid fa-book" :style="groupIconStyle"></i> 世界书候选</span>
            <button :style="addBtnStyle" @click="addWorldbookCandidate"><i class="fa-solid fa-plus"></i> 添加候选</button>
          </div>
          <div style="display: flex; flex-direction: column; gap: 10px">
            <div v-for="(candidate, index) in draft.worldbookCandidates" :key="`wb-${index}`" :style="subCardStyle">
              <div style="display: flex; align-items: center; gap: 10px; margin-bottom: 8px">
                <label
                  :style="{
                    display: 'inline-flex',
                    alignItems: 'center',
                    gap: '6px',
                    padding: '5px 11px',
                    borderRadius: '999px',
                    cursor: 'pointer',
                    fontSize: '12px',
                    fontWeight: 600,
                    background: candidate.enabled ? 'rgba(48,209,88,0.2)' : 'rgba(235,235,245,0.12)',
                    color: candidate.enabled ? '#5fe07f' : 'rgba(235,235,245,0.7)',
                  }"
                >
                  <input v-model="candidate.enabled" type="checkbox" style="width: auto; margin: 0; accent-color: #30d158" />
                  写入
                </label>
                <select v-model="candidate.type" :style="inputStyle" style="flex: 0 0 auto; width: auto; padding-right: 28px">
                  <option value="character">角色</option>
                  <option value="location">地点</option>
                  <option value="plot">剧情</option>
                  <option value="setting">设定</option>
                  <option value="item">物品</option>
                  <option value="other">其他</option>
                </select>
                <span style="flex: 1"></span>
                <button :style="delIconStyle" @click="draft.worldbookCandidates.splice(index, 1)"><i class="fa-solid fa-trash"></i></button>
              </div>
              <input v-model="candidate.title" placeholder="世界书条目标题" :style="inputStyle" style="margin-bottom: 8px" />
              <textarea v-model="candidate.content" placeholder="世界书条目内容" :style="textareaStyle"></textarea>
            </div>
            <div v-if="!draft.worldbookCandidates.length" :style="emptyHintStyle">暂无候选</div>
          </div>
        </div>
      </div>

      <!-- Footer -->
      <div
        style="
          display: flex;
          align-items: center;
          justify-content: flex-end;
          flex-wrap: wrap;
          gap: 9px;
          padding: 14px 18px;
          border-top: 0.5px solid rgba(255, 255, 255, 0.09);
          background: rgba(0, 0, 0, 0.2);
        "
      >
        <button :style="secondaryBtnStyle" @click="$emit('copy-json', draft)"><i class="fa-solid fa-code"></i> JSON</button>
        <button :style="secondaryBtnStyle" @click="$emit('copy-markdown', draft)"><i class="fa-brands fa-markdown"></i> Markdown</button>
        <button :style="secondaryBtnStyle" @click="$emit('generate-candidates', draft)"><i class="fa-solid fa-wand-magic-sparkles"></i> 补候选</button>
        <button :style="secondaryBtnStyle" @click="$emit('save', draft)"><i class="fa-solid fa-floppy-disk"></i> 保存</button>
        <button :style="primaryBtnStyle" @click="$emit('write-worldbook', draft)"><i class="fa-solid fa-book-bookmark"></i> 写入世界书</button>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { reactive, watch } from 'vue';
import { createEmptyVisualSummary, type VisualSummary } from '../types/visual-summary';

const props = defineProps<{
  show: boolean;
  summary: VisualSummary | null;
}>();

defineEmits<{
  close: [];
  save: [summary: VisualSummary];
  'copy-json': [summary: VisualSummary];
  'copy-markdown': [summary: VisualSummary];
  'generate-candidates': [summary: VisualSummary];
  'write-worldbook': [summary: VisualSummary];
}>();

// ===== 内联样式（规避 style.css 缓存）=====
const groupStyle =
  'border-radius: 16px; background: rgba(44,44,46,0.55); border: 0.5px solid rgba(255,255,255,0.08); padding: 14px 15px;';
const groupTitleStyle =
  'display: flex; align-items: center; gap: 8px; margin-bottom: 11px; color: rgba(235,235,245,0.6); font-size: 12.5px; font-weight: 600; letter-spacing: 0.3px;';
const groupHeadRowStyle =
  'display: flex; align-items: center; justify-content: space-between; gap: 10px; margin-bottom: 11px;';
const groupTitleInlineStyle =
  'display: inline-flex; align-items: center; gap: 8px; color: rgba(235,235,245,0.6); font-size: 12.5px; font-weight: 600; letter-spacing: 0.3px;';
const groupIconStyle = 'color: #0a84ff; font-size: 12px;';
const subCardStyle = 'padding: 12px 13px; border-radius: 12px; background: rgba(255,255,255,0.05);';
const inputStyle =
  'width: 100%; box-sizing: border-box; border: 0.5px solid rgba(255,255,255,0.12); border-radius: 10px; background: rgba(255,255,255,0.06); color: #f5f5f7; padding: 10px 12px; outline: none; font-size: 14px; font-family: inherit;';
const textareaStyle =
  'width: 100%; box-sizing: border-box; border: 0.5px solid rgba(255,255,255,0.12); border-radius: 10px; background: rgba(255,255,255,0.06); color: #f5f5f7; padding: 10px 12px; outline: none; font-size: 14px; min-height: 76px; resize: vertical; line-height: 1.55; font-family: inherit;';
const numBadgeStyle =
  'flex: 0 0 auto; min-width: 24px; height: 24px; padding: 0 6px; border-radius: 7px; background: rgba(10,132,255,0.18); color: #4ea1ff; font-size: 12px; font-weight: 700; display: inline-flex; align-items: center; justify-content: center;';
const emptyHintStyle = 'color: rgba(235,235,245,0.35); font-size: 13px; padding: 6px 2px;';
const addBtnStyle =
  'border: none; border-radius: 9px; cursor: pointer; background: rgba(10,132,255,0.18); color: #4ea1ff; padding: 6px 12px; font-size: 12.5px; font-weight: 600; display: inline-flex; align-items: center; gap: 5px;';
const delIconStyle =
  'flex: 0 0 auto; border: none; border-radius: 9px; cursor: pointer; background: rgba(255,69,58,0.16); color: #ff6961; padding: 9px 11px; font-size: 13px;';
const iconBtnStyle =
  'flex: 0 0 auto; border: none; border-radius: 50%; cursor: pointer; background: rgba(255,255,255,0.1); color: rgba(235,235,245,0.8); width: 32px; height: 32px; font-size: 15px;';
const secondaryBtnStyle =
  'border: none; border-radius: 11px; cursor: pointer; background: rgba(255,255,255,0.1); color: #f5f5f7; padding: 9px 14px; font-size: 13px; font-weight: 500; display: inline-flex; align-items: center; gap: 6px;';
const primaryBtnStyle =
  'border: none; border-radius: 11px; cursor: pointer; background: #0a84ff; color: #fff; padding: 9px 16px; font-size: 13px; font-weight: 600; display: inline-flex; align-items: center; gap: 6px;';

const draft = reactive<VisualSummary>({
  title: '',
  range: { start: 0, end: 0 },
  time: '',
  location: '',
  overview: '',
  events: [],
  characters: [],
  relationshipChanges: [],
  foreshadowing: [],
  todo: [],
  worldbookCandidates: [],
});

function loadSummary(summary: VisualSummary | null) {
  const empty = createEmptyVisualSummary(0, 0);
  Object.assign(draft, JSON.parse(JSON.stringify(summary || empty)));
}

watch(
  () => props.summary,
  summary => loadSummary(summary),
  { immediate: true, deep: true },
);

function addCharacter() {
  draft.characters.push({ name: '', status: '', attitude: '', memory: '' });
}

function addRelation() {
  draft.relationshipChanges.push({ from: '', to: '', change: '', reason: '' });
}

function addWorldbookCandidate() {
  draft.worldbookCandidates.push({ type: 'other', title: '', content: '', enabled: true });
}
</script>
